const n=()=>({formatDate:o=>new Date(o).toLocaleDateString("en-US",{month:"short",day:"numeric",year:"numeric"}),timeAgo:o=>{const e=Math.floor((new Date().getTime()-new Date(o).getTime())/1e3);let t=e/31536e3;return t>1?Math.floor(t)+"y ago":(t=e/2592e3,t>1?Math.floor(t)+"m ago":(t=e/86400,t>1?Math.floor(t)+"d ago":(t=e/3600,t>1?Math.floor(t)+"h ago":(t=e/60,t>1?Math.floor(t)+"min ago":Math.floor(e)+"s ago"))))}});export{n as u};
